dashboard.definition:
{
  "title": "Building Systems",
  "description": "NAKATOMI PLAZA — BUILDING MANAGEMENT SYSTEM",
  "dataSources": {
    "ds_results": {
      "type": "ds.search",
      "options": {
        "query": "$spl_query$ | fields - _bkt _cd _indextime _raw _serial _si _subsecond _sourcetype host index linecount source sourcetype splunk_server",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Query Results"
    },
    "ds_system_summary": {
      "type": "ds.search",
      "options": {
        "query": "index=nakatomi_building | stats count by system | sort -count",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "System Summary"
    },
    "ds_recent": {
      "type": "ds.search",
      "options": {
        "query": "index=nakatomi_building | head 15 | table _time system floor event value message",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Recent Building Events"
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "```\n> NAKATOMI PLAZA — BUILDING MANAGEMENT SYSTEM v2.0\n> INDEX: nakatomi_building\n> SOURCETYPES: HVAC / SECURITY CAMERA / ELEVATOR / POWER / SECURITY\n> ──────────────────────────────────────────────────────────\n> *** AMBER ALERT: ANOMALOUS READINGS DETECTED ***\n```",
        "fontColor": "#d4a843",
        "backgroundColor": "#0d0800"
      }
    },
    "viz_results": {
      "type": "splunk.table",
      "title": "> QUERY OUTPUT",
      "dataSources": {"primary": "ds_results"},
      "options": {
        "count": 50,
        "backgroundColor": "#0d0800"
      }
    },
    "viz_sidebar_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## > SUBSYSTEM STATUS",
        "fontColor": "#d4a843",
        "backgroundColor": "#0d0800"
      }
    },
    "viz_system_summary": {
      "type": "splunk.table",
      "title": "EVENTS BY SYSTEM",
      "dataSources": {"primary": "ds_system_summary"},
      "options": {
        "count": 20,
        "backgroundColor": "#0d0800"
      }
    },
    "viz_recent": {
      "type": "splunk.table",
      "title": "RECENT BUILDING EVENTS",
      "dataSources": {"primary": "ds_recent"},
      "options": {
        "count": 15,
        "backgroundColor": "#0d0800"
      }
    },
    "viz_fields": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "**SOURCETYPES:**\n`nakatomi:building:hvac` `nakatomi:security:camera`\n`nakatomi:building:elevator` `nakatomi:building:power`\n`nakatomi:building:security`\n\n**KEY FIELDS:**\n`system` `floor` `event` `event_type` `value`\n`message` `encoded_message` `camera_id` `zone`\n`elevator_id` `override_code` `status`\n\n**LOOKUPS:**\n`| inputlookup camera_coverage.csv`\n`| inputlookup floor_directory.csv`\n\n**EXAMPLE QUERIES:**\n```\nindex=nakatomi_building floor=roof\n  sourcetype=\"nakatomi:building:hvac\"\nindex=nakatomi_building\n  sourcetype=\"nakatomi:security:camera\"\n  floor=30 event_type=guard_patrol\nindex=nakatomi_building\n  sourcetype=\"nakatomi:building:elevator\"\n  action=override\nindex=nakatomi_building\n  sourcetype=\"nakatomi:building:power\"\n  status=active\n```",
        "fontColor": "#9a7020",
        "backgroundColor": "#0d0800"
      }
    },
    "viz_warning": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "```\n> ALERT: ROOF HVAC TEMPERATURE SPIKE DETECTED\n> ALERT: UNAUTHORIZED RADIO TRAFFIC ON SECURE CHANNELS\n> \"The building talks in code.\"\n```",
        "fontColor": "#ff3333",
        "backgroundColor": "#0d0000"
      }
    }
  },
  "inputs": {
    "input_spl": {
      "type": "input.text",
      "options": {
        "token": "spl_query",
        "defaultValue": "index=nakatomi_building | head 20 | table _time system floor event value message"
      },
      "title": "> ENTER SPL QUERY"
    }
  },
  "defaults": {
    "tokens": {
      "spl_query": "index=nakatomi_building | head 20 | table _time system floor event value message"
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": [],
    "structure": [
      {"item": "viz_header", "type": "block", "position": {"x": 0, "y": 0, "w": 1200, "h": 120}},
      {"item": "input_spl", "type": "block", "position": {"x": 0, "y": 120, "w": 1200, "h": 70}},
      {"item": "viz_results", "type": "block", "position": {"x": 0, "y": 190, "w": 820, "h": 500}},
      {"item": "viz_sidebar_header", "type": "block", "position": {"x": 820, "y": 190, "w": 380, "h": 50}},
      {"item": "viz_system_summary", "type": "block", "position": {"x": 820, "y": 240, "w": 380, "h": 230}},
      {"item": "viz_fields", "type": "block", "position": {"x": 820, "y": 470, "w": 380, "h": 450}},
      {"item": "viz_recent", "type": "block", "position": {"x": 0, "y": 690, "w": 820, "h": 330}},
      {"item": "viz_warning", "type": "block", "position": {"x": 0, "y": 1020, "w": 1200, "h": 80}}
    ]
  }
}
